mapper.select:
SELECT planInfo.plan_id,planInfo.plan_title,planTypeItem.item_text AS plan_type,planInfo.user_id, (SELECT GROUP_CONCAT( userInfo.`name` ) FROM sys_user userInfo WHERE FIND_IN_SET( userInfo.user_id, planInfo.user_id )) AS `name`, planInfo.target_user,planInfo.plan_begin_time,planInfo.plan_end_time, planInfo.plan_place,planInfo.plan_content,userPlanInfo.partake_status FROM t_plan_info planInfo LEFT JOIN t_dict_item planTypeItem ON planInfo.plan_type = planTypeItem.item_id LEFT JOIN t_user_plan_info userPlanInfo ON planInfo.plan_id = userPlanInfo.plan_id AND userPlanInfo.user_id=#{planInfo.partakeUserId}
AND planInfo.plan_title LIKE concat(concat('%',#{planInfo.planTitle}),'%')
AND planInfo.user_id =#{planInfo.userId}
AND planInfo.plan_type =#{planInfo.planType}
AND DATE_FORMAT(planInfo.plan_begin_time, '%Y-%m-%d %H:%i:%S') > DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%S')
AND DATE_FORMAT(planInfo.plan_begin_time, '%Y-%m-%d %H:%i:%S') < DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%S') AND DATE_FORMAT(planInfo.plan_end_time, '%Y-%m-%d %H:%i:%S') > DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%S')
AND DATE_FORMAT(planInfo.plan_end_time, '%Y-%m-%d %H:%i:%S') < DATE_FORMAT(NOW(), '%Y-%m-%d %H:%i:%S')
AND ISNULL(userPlanInfo.partake_status)
AND userPlanInfo.partake_status=#{planInfo.partakeStatus}
ORDER BY planInfo.create_time DESC
